from sqlalchemy import Column, BIGINT, Integer, String, DECIMAL, DateTime, ForeignKeyfrom sqlalchemy.sql import funcfrom sqlalchemy.ext.declarative import declarative_basefrom sqlalchemy.orm import relationshipBase = declarative_base()class BusLine(Base):    __tablename__ = "bus_lines"    line_id = Column(BIGINT, primary_key=True, autoincrement=True)    line_name = Column(String(100), nullable=False)    line_code = Column(String(20), unique=True, nullable=False, index=True)    start_station = Column(String(100))    end_station = Column(String(100))    total_stations = Column(Integer, default=0)    distance_km = Column(DECIMAL(10, 2), default=0.0)    first_departure_time = Column(String(10))    last_departure_time = Column(String(10))    interval_minutes = Column(Integer, default=10)    status = Column(String(20), nullable=False, default='active')    created_at = Column(DateTime, nullable=False, server_default=func.now())class BusStation(Base):    __tablename__ = "bus_stations"    station_id = Column(BIGINT, primary_key=True, autoincrement=True)    station_name = Column(String(100), nullable=False)    station_code = Column(String(20), unique=True, nullable=False, index=True)    latitude = Column(DECIMAL(10, 7), nullable=False)    longitude = Column(DECIMAL(10, 7), nullable=False)    address = Column(String(255))    zone = Column(String(50))    created_at = Column(DateTime, nullable=False, server_default=func.now())class LineStation(Base):    __tablename__ = "line_stations"    id = Column(BIGINT, primary_key=True, autoincrement=True)    line_id = Column(BIGINT, ForeignKey("bus_lines.line_id"))    station_id = Column(BIGINT, ForeignKey("bus_stations.station_id"))    order_index = Column(Integer, nullable=False)    direction = Column(String(10))    line = relationship("BusLine")    station = relationship("BusStation")